func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("GET "+options.BaseURL+"/api/platform/forums", wrapper.ListForums)
	m.HandleFunc("POST "+options.BaseURL+"/api/platform/forums", wrapper.ProvisionForum)
	m.HandleFunc("GET "+options.BaseURL+"/api/platform/forums/{slug}/export", wrapper.ExportForum)
	m.HandleFunc("GET "+options.BaseURL+"/api/platform/owned-sites", wrapper.ListOwnedSites)
	m.HandleFunc("GET "+options.BaseURL+"/api/platform/sites/{slug}/files", wrapper.ListFiles)
	m.HandleFunc("DELETE "+options.BaseURL+"/api/platform/sites/{slug}/files/{path}", wrapper.DeleteFile)
	m.HandleFunc("GET "+options.BaseURL+"/api/platform/sites/{slug}/files/{path}", wrapper.GetFile)
	m.HandleFunc("PUT "+options.BaseURL+"/api/platform/sites/{slug}/files/{path}", wrapper.PutFile)
	m.HandleFunc("POST "+options.BaseURL+"/api/platform/sites/{slug}/reset", wrapper.ResetSite)
	m.HandleFunc("POST "+options.BaseURL+"/api/platform/sites/{slug}/upload", wrapper.MultipartUpload)

	return m
}

