// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// List all active hosted forums
	// (GET /api/platform/forums)
	ListForums(ctx context.Context, request ListForumsRequestObject) (ListForumsResponseObject, error)
	// Provision a new hosted forum
	// (POST /api/platform/forums)
	ProvisionForum(ctx context.Context, request ProvisionForumRequestObject) (ProvisionForumResponseObject, error)
	// Export forum data as JSON
	// (GET /api/platform/forums/{slug}/export)
	ExportForum(ctx context.Context, request ExportForumRequestObject) (ExportForumResponseObject, error)
	// List forums owned by the caller
	// (GET /api/platform/owned-sites)
	ListOwnedSites(ctx context.Context, request ListOwnedSitesRequestObject) (ListOwnedSitesResponseObject, error)
	// List custom site files
	// (GET /api/platform/sites/{slug}/files)
	ListFiles(ctx context.Context, request ListFilesRequestObject) (ListFilesResponseObject, error)
	// Delete a custom site file
	// (DELETE /api/platform/sites/{slug}/files/{path})
	DeleteFile(ctx context.Context, request DeleteFileRequestObject) (DeleteFileResponseObject, error)
	// Download a custom site file
	// (GET /api/platform/sites/{slug}/files/{path})
	GetFile(ctx context.Context, request GetFileRequestObject) (GetFileResponseObject, error)
	// Upload or replace a custom site file
	// (PUT /api/platform/sites/{slug}/files/{path})
	PutFile(ctx context.Context, request PutFileRequestObject) (PutFileResponseObject, error)
	// Reset custom site to default
	// (POST /api/platform/sites/{slug}/reset)
	ResetSite(ctx context.Context, request ResetSiteRequestObject) (ResetSiteResponseObject, error)
	// Upload multiple files via multipart form
	// (POST /api/platform/sites/{slug}/upload)
	MultipartUpload(ctx context.Context, request MultipartUploadRequestObject) (MultipartUploadResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// ListForums operation middleware
func (sh *strictHandler) ListForums(w http.ResponseWriter, r *http.Request) {
	var request ListForumsRequestObject

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.ListForums(ctx, request.(ListForumsRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "ListForums")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(ListForumsResponseObject); ok {
		if err := validResponse.VisitListForumsResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

